1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { items: Array<{ type: string }> }): { premium: number } {
16	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
17	
18	  const componentCounts: Record<string, number> = {};
19	  let base = 0;
20	  for (const item of input.items) {
21	    if (COMPONENT_TYPES.has(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
23	    } else {
24	      base += BASE_PREMIUMS[item.type];
25	    }
26	  }
27	  for (const [type, count] of Object.entries(componentCounts)) {
28	    base += count === 3 ? 60 : count * BASE_PREMIUMS[type];
29	  }
30	
31	  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
32	}
33	
34	export function claim(_input: unknown): unknown {
35	  return undefined;
36	}
